(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[471],{997:function(e,t,o){Promise.resolve().then(o.bind(o,5324))},5324:function(e,t,o){"use strict";o.r(t),o.d(t,{default:function(){return r}});var i=o(7821),n=o(8078),a=o(3197);let s={slug:"mental-health",title:"Understanding & Managing Anxiety and Depression",subtitle:"Buffington Family Medicine",accentColor:"#7c3aed",accentColorLight:"#ede9fe",heroDescription:"You are not alone. Anxiety and depression are among the most common conditions we treat, and effective help is available. This guide was created by your care team at Buffington Family Medicine to walk you through every step of your treatment journey — from your first appointment to long-term wellness.",navItems:[{id:"overview",label:"Overview"},{id:"start",label:"Start Here"},{id:"first-weeks",label:"First Few Weeks"},{id:"understanding",label:"Understanding"},{id:"treatment",label:"Treatment Options"},{id:"medications",label:"Medications"},{id:"timeline",label:"Timeline"},{id:"side-effects",label:"Side Effects"},{id:"not-helping",label:"Not Helping Yet?"},{id:"between-visits",label:"Between Visits"},{id:"urgent-help",label:"Urgent Help"},{id:"self-care",label:"Self-Care"},{id:"supporting-others",label:"Supporting Others"},{id:"med-worries",label:"Common Worries"},{id:"faqs",label:"FAQs"},{id:"resources",label:"Resources"},{id:"updates",label:"Updates"},{id:"next-steps",label:"Next Steps"}],sections:[{id:"overview",title:"Welcome",content:[{type:"callout",variant:"info",title:"How to use this page",body:"Start with the **Start Here** section if this is your first visit. Jump to **FAQs** anytime you have a quick question. Find your **Next Steps** at the bottom. Bookmark this page and come back to it as an ongoing reference — it is always here for you."},{type:"text",body:"If you're reading this, you've already taken an important step. Whether you're exploring treatment for the first time or continuing a journey you started elsewhere, we're glad you're here."},{type:"text",body:"**Anxiety and depression affect millions of people** — and they are very treatable. At Buffington Family Medicine, we approach mental health the same way we approach every other part of your health: with compassion, evidence-based care, and a plan built around **you**."},{type:"heading",level:3,text:"Most important things to know"},{type:"bullets",items:["**Your first step** is to take your medication as prescribed and give it time — most medications take 2-4 weeks to start working","**Mild side effects in the first week are normal** and usually improve quickly","**Follow up in 2-4 weeks** so we can check your response and adjust if needed","**Do not stop your medication on your own** — call us first, even if you are feeling better","**Contact our office at (817) 431-9199** if symptoms worsen, you feel significantly worse, or you have thoughts of self-harm"]},{type:"callout",variant:"urgent",title:"When to call us or get help immediately",body:"Call **(817) 431-9199** right away if you experience worsening thoughts of self-harm, severe panic that won't subside, or feel unable to care for yourself. For life-threatening emergencies, call **911** or text **988**. Full details are in the **Urgent Help** section."},{type:"callout",variant:"info",title:"You are not alone",body:"Nearly 1 in 5 U.S. adults live with a mental health condition. Seeking help is a sign of strength, not weakness. Our team is here to support you every step of the way."},{type:"heading",level:3,text:"What this guide covers"},{type:"bullets",items:["What to expect from your first appointment and the first few weeks of treatment","How anxiety and depression work — and how they differ","Medication options, how they work, and realistic timelines","Managing side effects and knowing when to reach out","What to do between visits","Self-care strategies that support your treatment","How to help a loved one who is struggling","Crisis resources and urgent safety information"]},{type:"text",body:"You can read this guide from start to finish or jump to the section that matters most to you right now. Come back to it anytime — it's always here for you."}]},{id:"start",title:"Start Here",content:[{type:"text",body:"Starting treatment can feel overwhelming. Here's exactly what to expect so there are no surprises."},{type:"heading",level:3,text:"Your first step"},{type:"text",body:"**Your first step is to pick up your prescription and start taking it as directed.** Take it at the same time each day. If your provider recommended therapy, your next step is to schedule your first therapy appointment."},{type:"heading",level:3,text:"Your first appointment"},{type:"text",body:"Your first visit is a conversation. We'll talk about how you've been feeling, what's been going on in your life, your medical history, and what you'd like to get out of treatment. **There are no wrong answers** — the more honest you can be, the better we can help."},{type:"numbered",items:["**Check in** — Our front desk will greet you and get you settled. You may be asked to fill out a brief questionnaire (PHQ-9 or GAD-7) about your symptoms.","**Meet with your provider** — We'll review your symptoms, history, and any previous treatments. This is your time to ask questions and share what's on your mind.","**Build a plan together** — Based on our conversation, we'll recommend a treatment approach. This might include medication, therapy referrals, lifestyle changes, or a combination.","**Schedule follow-up** — We typically see you back in 2-4 weeks to check on how you're doing and make any adjustments."]},{type:"callout",variant:"info",title:"What to bring",body:"A list of any current medications (including supplements), notes about your symptoms and how long they've been going on, and any questions you'd like to ask. If you've had treatment before, let us know what helped and what didn't."},{type:"heading",level:3,text:"Your next step: How medication management works"},{type:"text",body:"If we decide together that medication is a good fit, here's how the process works:"},{type:"numbered",items:["**We start low and go slow** — Most medications are started at a low dose to minimize side effects, then gradually increased to find your ideal dose.","**Regular check-ins** — We'll schedule follow-up appointments (typically every 2-4 weeks at first) to monitor how you're responding.","**Adjustments are normal** — It's common to adjust the dose or even try a different medication. This doesn't mean something is wrong — everyone responds differently.","**Open communication** — Call us between appointments if something doesn't feel right. You don't have to wait for your next visit."]},{type:"text",body:"Our goal is to find the approach that helps you feel like yourself again — with the fewest side effects possible."}]},{id:"first-weeks",title:"What to Expect in the First Few Weeks",content:[{type:"text",body:"The first few weeks of treatment are an adjustment period. Knowing what to expect can make this phase much easier."},{type:"heading",level:3,text:"Week 1: Getting started"},{type:"bullets",items:["You probably **will not feel better yet** — this is completely normal","You may notice mild side effects like nausea, headache, or sleep changes","Most early side effects improve within a few days to a week","**Keep taking the medication as prescribed** even if you do not notice improvement"]},{type:"heading",level:3,text:"Week 2-3: Early changes"},{type:"bullets",items:["Sleep and energy may start to improve before mood does","You may have both good days and hard days — this is part of the process","Others around you may notice improvements before you do","Side effects should be fading — if they are not, call our office"]},{type:"heading",level:3,text:"Week 4+: Follow-up time"},{type:"bullets",items:["By now you should notice some meaningful improvement","Your provider will review how you are doing and may adjust the dose","If you do not feel better, **do not give up** — we have many options to try","Dose changes and medication switches are a normal part of finding the right fit"]},{type:"callout",variant:"info",title:"When to contact our office between visits",body:"Call **(817) 431-9199** if: side effects are significant or not improving, you feel noticeably worse, you have new or worsening anxiety, or you have any thoughts of self-harm. **You do not need to wait for your next appointment.**"}]},{id:"understanding",title:"Understanding Anxiety & Depression",content:[{type:"text",body:'Anxiety and depression are not character flaws or something you can simply "snap out of." They are real medical conditions that involve changes in brain chemistry, and they respond to treatment just like other health conditions.'},{type:"heading",level:3,text:"What is depression?"},{type:"text",body:"Depression is more than feeling sad. It's a persistent change in mood and energy that interferes with daily life."},{type:"bullets",items:["Persistent sadness, emptiness, or hopelessness","Loss of interest or pleasure in activities","Changes in appetite or weight","Sleeping too much or too little","Fatigue or loss of energy","Difficulty concentrating or making decisions","Feelings of worthlessness or excessive guilt","Withdrawal from friends, family, or social activities","Irritability, anger, or frustration — even over small things","Unexplained physical problems such as back pain or headaches","Recurrent thoughts of death or suicide"]},{type:"heading",level:3,text:"Types of depression"},{type:"text",body:"Depression is not a single condition — it comes in several forms. Recognizing which type fits your experience helps us choose the most effective treatment."},{type:"bullets",items:["**Major depressive disorder** — the most common form, with persistent symptoms lasting at least two weeks that significantly interfere with daily life",'**Persistent depressive disorder (dysthymia)** — a lower-grade but chronic depression lasting two years or more. You may feel like you\'ve "always been this way"',"**Seasonal affective disorder (SAD)** — depression that follows a seasonal pattern, typically worsening in fall/winter",'**Postpartum depression** — depression during pregnancy or after delivery. More than "baby blues" and requires treatment',"**Depression with anxious distress** — major depression accompanied by significant anxiety and restlessness","**Bipolar disorder** — episodes of depression alternating with elevated mood (mania). Requires different medication than standard depression"]},{type:"callout",variant:"info",title:"If this sounds like you",body:"You do not need to diagnose yourself. If any of these descriptions resonate with your experience, bring it up at your visit. Knowing which type of depression you have helps us choose the right treatment — and some types (like bipolar disorder) require different medications than others."},{type:"heading",level:3,text:"What is anxiety?"},{type:"text",body:"Anxiety goes beyond normal worry. It's excessive, persistent worry or fear that is difficult to control and interferes with everyday activities. Physical symptoms — racing heart, muscle tension, stomach problems — are very common."},{type:"bullets",items:["Excessive worry that's hard to control","Restlessness or feeling on edge","Racing heart, sweating, or trembling","Muscle tension and headaches","Difficulty sleeping or staying asleep","Irritability","Trouble concentrating or mind going blank","Avoidance of situations that trigger anxiety","Feeling of impending danger, panic, or doom","Stomach problems, nausea, or digestive issues"]},{type:"heading",level:3,text:"Types of anxiety disorders"},{type:"bullets",items:["**Generalized anxiety disorder (GAD)** — persistent, excessive worry about many different things that is difficult to control, occurring most days for at least six months","**Panic disorder** — recurrent, unexpected panic attacks with intense physical symptoms. Many patients first go to the ER thinking they are having a heart attack","**Social anxiety disorder** — intense fear of social situations and being judged. Goes far beyond normal shyness","**Specific phobias** — extreme fear of a particular object or situation that is out of proportion to the actual danger","**Agoraphobia** — fear and avoidance of places or situations where escape might be difficult or help might not be available"]},{type:"callout",variant:"info",title:"Anxiety can look like a medical problem",body:"Many medical conditions can cause or mimic anxiety symptoms — including thyroid disorders, heart conditions, and respiratory conditions. This is one reason we do a thorough evaluation before diagnosing anxiety. If your anxiety started suddenly, tell your provider so we can rule out medical causes."},{type:"heading",level:3,text:"How they overlap"},{type:"text",body:"It's extremely common to experience **both anxiety and depression at the same time**. More than half of people diagnosed with depression also have significant anxiety symptoms. The good news is that many treatments — including the medications we prescribe — are effective for both conditions."},{type:"heading",level:3,text:"Common misconceptions"},{type:"bullets",items:['**"It\'s all in your head."** — Anxiety and depression involve real changes in brain chemistry. They are as real as diabetes or high blood pressure.','**"You should be able to handle it on your own."** — Asking for help is smart, not weak. You wouldn\'t set a broken bone yourself.','**"Medication changes who you are."** — The right medication helps you feel more like yourself, not less.','**"If you need medication, you\'ve failed."** — Medication is a tool, like glasses for your eyes.','**"You\'ll need medication forever."** — Many people use medication for a period of time, then taper off successfully.']}]},{id:"treatment",title:"Treatment Options",content:[{type:"text",body:"There is no one-size-fits-all approach to treating anxiety and depression. At Buffington Family Medicine, we build a plan tailored to you — your symptoms, your preferences, and your life."},{type:"heading",level:3,text:"Medication"},{type:"text",body:"Medications like SSRIs and SNRIs are among the most effective and well-studied treatments for anxiety and depression. They work by adjusting the balance of natural chemicals (neurotransmitters) in your brain. We'll cover these in detail in the **Medications** section."},{type:"heading",level:3,text:"Therapy / Counseling"},{type:"text",body:"Talk therapy — especially **Cognitive Behavioral Therapy (CBT)** — has strong evidence for treating both anxiety and depression. Therapy gives you tools to recognize unhelpful thought patterns, develop coping strategies, and build resilience. We can provide referrals to therapists in the Flower Mound area."},{type:"heading",level:3,text:"Lifestyle changes"},{type:"text",body:"Regular exercise, quality sleep, stress management, and social connection all have a meaningful impact on anxiety and depression. These aren't substitutes for medication or therapy when those are needed, but they're powerful partners in your recovery."},{type:"heading",level:3,text:"The combination approach"},{type:"callout",variant:"info",title:"Research consistently shows",body:"The combination of medication and therapy tends to produce the best outcomes for moderate to severe anxiety and depression. Medication can lift you to a place where therapy and lifestyle changes become more effective — and those tools help sustain your improvement long-term."},{type:"text",body:"We'll work with you to find the right combination. Some people do well with medication alone, some with therapy alone, and many benefit from both together. **Your treatment plan can evolve over time** as your needs change."}]},{id:"medications",title:"Medications",content:[{type:"text",body:"The medications most commonly used for anxiety and depression belong to two main classes: **SSRIs** (Selective Serotonin Reuptake Inhibitors) and **SNRIs** (Serotonin-Norepinephrine Reuptake Inhibitors). We also sometimes use **bupropion**, which works differently from both."},{type:"heading",level:3,text:"How SSRIs and SNRIs work"},{type:"text",body:"Your brain uses chemical messengers called neurotransmitters — including **serotonin** and **norepinephrine** — to regulate mood, sleep, appetite, and anxiety. When these chemicals are out of balance, symptoms of depression and anxiety can develop."},{type:"text",body:"SSRIs and SNRIs work by preventing your brain from reabsorbing these neurotransmitters too quickly, allowing them to remain active longer. This helps restore balance over time. **They don't create artificial happiness** — they help your brain function the way it's supposed to."},{type:"heading",level:3,text:"Why they take time"},{type:"text",body:"Unlike a pain reliever that works in 30 minutes, antidepressants need time to build up in your system. Most people begin noticing improvement in **2-4 weeks**, with full effects at **6-8 weeks**. This is normal and expected — not a sign that the medication isn't working."},{type:"heading",level:3,text:"Common medications we prescribe"},{type:"table",headers:["Medication","Class","Common Uses","Typical Starting Dose"],rows:[["Sertraline (Zoloft)","SSRI","Depression, anxiety, panic, PTSD, OCD","25-50 mg daily"],["Escitalopram (Lexapro)","SSRI","Depression, generalized anxiety","5-10 mg daily"],["Duloxetine (Cymbalta)","SNRI","Depression, anxiety, chronic pain","20-30 mg daily"],["Venlafaxine (Effexor XR)","SNRI","Depression, anxiety, panic","37.5-75 mg daily"],["Bupropion (Wellbutrin)","NDRI","Depression, low energy, smoking cessation","150 mg daily"]]},{type:"callout",variant:"info",title:"Choosing the right medication",body:"We choose a medication based on your specific symptoms, other health conditions, current medications, previous treatment history, and potential side effects. If one medication isn't the right fit, there are many options to try. Our team will guide you through the process."},{type:"heading",level:3,text:"A note about bupropion"},{type:"text",body:"Bupropion works on different brain chemicals (dopamine and norepinephrine) than SSRIs and SNRIs. It's a good option for people who experience fatigue or low motivation with depression, and it's **less likely to cause weight gain or sexual side effects**. However, it's generally not the first choice for anxiety, as it can sometimes increase anxious feelings."},{type:"heading",level:3,text:"Buspirone for anxiety"},{type:"text",body:"Buspirone is a non-addictive anti-anxiety medication specifically approved for **generalized anxiety disorder**. It can be used alone or alongside an antidepressant. Like SSRIs, it takes **2-4 weeks** to reach full effectiveness. It has fewer side effects than many alternatives and no risk of dependence."},{type:"heading",level:3,text:"Benzodiazepines (Xanax, Ativan, Klonopin)"},{type:"text",body:"Benzodiazepines are fast-acting anti-anxiety medications that work within 30-60 minutes. They can be very effective for acute anxiety or panic attacks. However, they carry important risks:"},{type:"bullets",items:["**Physical dependence** can develop with regular use, even at prescribed doses","**Tolerance** may build over time, requiring higher doses for the same effect","**Withdrawal** can be severe and even dangerous if stopped abruptly","**Sedation** — they cause drowsiness and impair driving and coordination","**Not recommended for long-term use** in most cases"]},{type:"text",body:"We may prescribe benzodiazepines for **short-term or occasional use** while waiting for an SSRI or buspirone to take effect, or for specific situations like severe panic attacks. They are not a first-line long-term solution."},{type:"callout",variant:"urgent",title:"Never stop a benzodiazepine abruptly",body:"If you are currently taking a benzodiazepine, **never stop it suddenly** — always taper under medical supervision. Abrupt discontinuation can be dangerous."}]},{id:"timeline",title:"Timeline for Improvement",content:[{type:"text",body:"Healing takes time, and everyone's journey is a little different. Here's a general roadmap of what to expect so you can track your progress and stay encouraged."},{type:"milestone",week:"Week 1-2",title:"Adjustment period",details:["Your body is getting used to the medication","You may notice some side effects (these often improve with time)","Sleep and appetite may begin to shift","Mood improvement is usually not noticeable yet — this is completely normal","**Keep taking the medication as prescribed** even if you don't feel different"]},{type:"milestone",week:"Week 3-4",title:"Early signs of improvement",details:["Many people start noticing subtle changes — better sleep, more energy, less intense worry","Others around you may notice changes before you do","Side effects often begin to fade","You may have both good days and hard days — this is part of the process"]},{type:"milestone",week:"Month 2-3",title:"Building momentum",details:["Mood improvements become more consistent","Anxiety feels more manageable","Concentration and motivation often return","We may adjust your dose during this period to optimize results","This is a great time to add therapy or strengthen self-care habits"]},{type:"milestone",week:"Month 3-6",title:"Stabilization",details:["Most people are feeling significantly better by this point","Your new baseline is established","Follow-up visits may become less frequent (every 2-3 months)","We'll discuss your long-term plan — how long to continue medication and next steps"]},{type:"callout",variant:"info",title:"Managing expectations",body:"Medication isn't a magic switch. Some people respond quickly, others take longer. If you don't feel better after 4-6 weeks at an adequate dose, that doesn't mean treatment has failed — it means we need to adjust. Don't stop taking your medication without talking to us first."}]},{id:"side-effects",title:"Side Effects",content:[{type:"text",body:"All medications can cause side effects. The good news is that most side effects from antidepressants are **mild and temporary**, often improving within the first 1-2 weeks as your body adjusts."},{type:"heading",level:3,text:"Common side effects (SSRIs/SNRIs)"},{type:"text",body:"These are the most frequently reported side effects. **Most resolve on their own** within the first couple of weeks:"},{type:"bullets",items:["**Nausea** — Taking medication with food often helps. Usually resolves within a week.","**Headache** — Typically mild and short-lived. Over-the-counter pain relief can help.","**Sleep changes** — Some people feel drowsy, others have difficulty sleeping. Adjusting the time you take your medication can help.","**Dizziness** — Usually mild. Rise slowly from sitting or lying positions.","**Dry mouth** — Sipping water throughout the day helps.","**Increased anxiety (first few days)** — Some people feel briefly more anxious when starting. This usually passes quickly."]},{type:"heading",level:3,text:"Side effects that may persist"},{type:"text",body:"Some side effects can last longer. If any of these bother you, **please tell us** — we have strategies to manage them:"},{type:"bullets",items:["**Weight changes** — Some medications may cause modest weight gain or loss. Bupropion is less likely to cause weight gain.","**Fatigue** — If ongoing drowsiness is a problem, we can adjust timing or consider alternatives.","**Sweating** — More common with SNRIs. Usually manageable."]},{type:"heading",level:3,text:"A note about sexual side effects"},{type:"callout",variant:"info",title:"Sexual side effects — let's talk about it",body:"SSRIs and SNRIs can affect sexual desire, arousal, or function. This is one of the most common reasons people stop taking medication without telling their provider. **Please don't suffer in silence.** We can adjust your dose, switch medications, or add strategies to help. Bupropion is much less likely to cause sexual side effects and is sometimes added alongside an SSRI for this reason."},{type:"heading",level:3,text:"When to call us right away"},{type:"text",body:"While serious side effects are rare, contact our office promptly if you experience:"},{type:"bullets",items:["Severe allergic reaction (rash, hives, swelling, difficulty breathing)","Significant increase in anxiety, agitation, or restlessness","New or worsening thoughts of self-harm","Unusual bleeding or bruising","Seizures","Severe nausea, vomiting, or diarrhea","Serotonin syndrome symptoms (confusion, rapid heart rate, high fever, muscle twitching)"]},{type:"callout",variant:"info",title:"Important for patients under 25",body:"In children, teenagers, and young adults under 25, antidepressants may occasionally increase thoughts of self-harm during the first few weeks of treatment. This is why we monitor closely during the early phase. If you or your child notice new or worsening thoughts of self-harm, contact us immediately or call 988."}]},{id:"not-helping",title:"What If Treatment Doesn't Help Right Away?",content:[{type:"text",body:"If you have been on medication for a few weeks and do not feel better, **that does not mean treatment has failed.** It means we are still finding the right fit for you."},{type:"heading",level:3,text:"What you should know"},{type:"bullets",items:["**The first medication is not always the final one.** Everyone's brain chemistry is different, and it is common to try more than one medication before finding the best match.","**Dose adjustments are part of the process.** We often start low and increase gradually. You may not be at the right dose yet.","**Improvement is often gradual.** You may not notice day-to-day changes, but looking back over a few weeks, you may realize things have shifted.","**Do not stop your medication on your own.** If you are thinking about stopping, call us first. Stopping abruptly can cause withdrawal symptoms and set back your progress."]},{type:"callout",variant:"info",title:"Communicate rather than quit",body:"The most important thing you can do is **keep us in the loop.** If something is not working, if side effects are bothering you, or if you just feel stuck — tell us. We would much rather adjust your plan than have you struggle in silence or stop treatment on your own."},{type:"heading",level:3,text:"What we can do"},{type:"numbered",items:["**Increase the dose** — you may simply need a higher dose to reach therapeutic levels","**Switch medications** — a different SSRI, SNRI, or another class may work better for you","**Add a second medication** — sometimes combining two medications produces better results","**Add therapy** — if you are not already in therapy, this can significantly boost your progress","**Review other factors** — sleep, stress, alcohol use, thyroid function, and other health conditions can all affect how well your medication works"]}]},{id:"between-visits",title:"What to Do Between Visits",content:[{type:"text",body:"Between appointments, there are a few simple things you can do to stay on track and help us help you at your next visit."},{type:"numbered",items:["**Continue your medication as directed** — take it at the same time each day. Do not skip doses or stop on your own.",'**Track your mood and sleep** — even a quick daily note on your phone ("good day" / "rough day" / "slept well" / "trouble sleeping") gives us useful information.',"**Note any side effects** — write down what you notice and when. This helps us decide if adjustments are needed.","**Keep up with self-care basics** — sleep, exercise, and social connection all support your treatment.","**Contact our office if symptoms worsen** — you do not need to wait for your next appointment. Call **(817) 431-9199**."]},{type:"callout",variant:"info",title:"Imperfect progress is still progress",body:"Recovery is not a straight line. You will have good days and hard days. That is completely normal. The goal is a general trend in the right direction — not perfection. If you miss a dose, skip a workout, or have a bad week, that does not erase your progress. Just keep going and stay in touch with our team."}]},{id:"urgent-help",title:"When to Seek Urgent Help",content:[{type:"callout",variant:"urgent",title:"If you or someone you know is in crisis",body:"You are not alone, and help is available right now.\n\n**988 Suicide & Crisis Lifeline** — Call or text **988** (available 24/7)\n\n**Crisis Text Line** — Text **HOME** to **741741**\n\n**Emergency** — Call **911** or go to your nearest emergency room\n\nIf you are in immediate danger, please call 911. These services are free, confidential, and available around the clock."},{type:"text",body:"It can be hard to know when worry or sadness has crossed a line into a crisis. **Trust your instincts.** If something feels wrong, it's always better to reach out."},{type:"heading",level:3,text:"Seek urgent help if you experience"},{type:"bullets",items:["Thoughts of suicide or self-harm","A plan or intent to hurt yourself or others","Feeling like your loved ones would be better off without you","Hearing voices or seeing things that aren't there","Severe panic that won't subside","Inability to care for yourself (not eating, drinking, or sleeping for days)","Sudden, dramatic mood changes or behavior that feels out of control"]},{type:"heading",level:3,text:"Safety planning"},{type:"text",body:"A safety plan is a personal list of coping strategies and contacts you can use during a crisis. We encourage everyone — not just those in acute distress — to have one. Talk to us at your next appointment about creating one together."},{type:"checklist",items:["Save 988 in your phone contacts","Identify 2-3 people you can call when you're struggling","Know the location of your nearest emergency room","Remove or secure access to anything that could be used for self-harm","Write down your personal warning signs (feelings or situations that signal you need help)","Keep this resource page bookmarked for easy access"]},{type:"heading",level:3,text:"Contacting our office"},{type:"text",body:"For non-emergency concerns between appointments, call Buffington Family Medicine at **(817) 431-9199** during business hours. If you're experiencing a mental health emergency outside of business hours, please call 988 or go to your nearest emergency room."}]},{id:"self-care",title:"Self-Care Strategies",content:[{type:"text",body:"Medication and therapy lay the foundation, but **daily habits play a huge role** in how you feel. These strategies aren't about being perfect — they're about giving yourself the best chance to heal and stay well."},{type:"heading",level:3,text:"Sleep hygiene"},{type:"text",body:"Sleep and mental health are deeply connected. Poor sleep worsens anxiety and depression, and both conditions make it harder to sleep. Breaking this cycle is one of the most impactful things you can do."},{type:"checklist",items:["Go to bed and wake up at the same time every day (even weekends)","Keep your bedroom cool, dark, and quiet","Avoid screens for 30-60 minutes before bed","Limit caffeine after noon","Skip alcohol close to bedtime (it disrupts sleep quality even if it helps you fall asleep)","If you can't sleep after 20 minutes, get up and do something calm until you feel sleepy"]},{type:"heading",level:3,text:"Exercise"},{type:"text",body:"Regular physical activity is one of the most powerful natural antidepressants available. **You don't need to run a marathon** — even a 20-minute walk makes a difference."},{type:"bullets",items:["Aim for 30 minutes of moderate activity most days","Walking, swimming, cycling, yoga, and dancing all count","Start small if you're not active — 10 minutes is better than zero","Exercising outdoors provides added benefits from sunlight and nature","Find something you enjoy — consistency matters more than intensity"]},{type:"heading",level:3,text:"Stress management"},{type:"bullets",items:["**Set boundaries** — It's okay to say no to things that drain you","**Break tasks into small steps** — When everything feels overwhelming, just do the next small thing","**Limit news and social media** — Constant information overload fuels anxiety","**Practice deep breathing** — Even 3-5 slow breaths can activate your body's calming response","**Write it down** — Journaling can help process difficult emotions and reduce rumination"]},{type:"heading",level:3,text:"Mindfulness"},{type:"text",body:"Mindfulness means paying attention to the present moment without judgment. Even 5 minutes a day can reduce anxiety and improve mood."},{type:"bullets",items:["Try a free app like Insight Timer, Headspace, or Calm","Start with guided meditations if sitting in silence feels hard","Practice the 5-4-3-2-1 grounding exercise (5 things you can see, 4 you can hear, 3 you can touch, 2 you can smell, 1 you can taste)","Mindful walking — focus on each step and the sensations in your body"]},{type:"heading",level:3,text:"Social connection"},{type:"text",body:"Depression and anxiety often make you want to withdraw — but isolation usually makes things worse. **Connection doesn't have to be big.** A short text to a friend, a brief phone call, or sitting in a coffee shop near other people all count."},{type:"callout",variant:"info",title:"Small steps matter",body:"You don't need to overhaul your entire life at once. Pick one or two strategies that feel manageable and build from there. Progress isn't always linear — be patient and gentle with yourself."}]},{id:"supporting-others",title:"Supporting a Loved One",content:[{type:"text",body:"Watching someone you care about struggle with anxiety or depression can feel helpless. You can't fix it for them, but your support matters more than you know."},{type:"heading",level:3,text:"What to do"},{type:"bullets",items:["**Listen without trying to fix** — Sometimes the most powerful thing you can do is simply be present.",'**Check in regularly** — A simple text or call to say "thinking of you" can break through the isolation.',"**Learn about their condition** — Understanding what they're going through helps you respond with empathy.","**Encourage treatment** — Gently support them in keeping appointments and taking medication. Offer to drive them.","**Be patient** — Recovery takes time. There will be setbacks. Your steady presence matters.","**Take care of yourself too** — Supporting someone with a mental health condition can be draining. Make sure you're getting your own needs met."]},{type:"heading",level:3,text:"What to say"},{type:"bullets",items:['"I may not fully understand what you\'re going through, but I care about you."','"You don\'t have to go through this alone."','"Is there anything I can do to help today?"',"\"I've noticed you seem like you're having a hard time. I'm here if you want to talk.\"",'"It\'s okay to not be okay."']},{type:"heading",level:3,text:"What NOT to say"},{type:"bullets",items:['"Just think positive" or "cheer up" — This dismisses their experience','"Other people have it worse" — Comparison doesn\'t help and can increase guilt',"\"You don't seem depressed\" — Depression doesn't always look the way people expect",'"Have you tried yoga / essential oils / etc.?" — Unsolicited advice can feel dismissive','"You just need to get out more" — If it were that simple, they would']},{type:"heading",level:3,text:"Recognizing warning signs"},{type:"text",body:"Pay attention to changes that might signal your loved one needs more help:"},{type:"bullets",items:["Withdrawing from people and activities they used to enjoy","Talking about being a burden or having no purpose","Giving away possessions or saying goodbye in unusual ways","Increased use of alcohol or drugs","Dramatic mood swings or sudden calmness after a period of depression","Expressing hopelessness about the future"]},{type:"callout",variant:"urgent",title:"If you believe someone is in immediate danger",body:"Call **911** or take them to the nearest emergency room. You can also call the **988 Suicide & Crisis Lifeline** (call or text 988) for guidance. Don't leave them alone. It is always better to overreact than to wait."}]},{id:"med-worries",title:"Common Early Medication Worries",content:[{type:"text",body:"Starting a new medication often comes with questions and concerns. Here are the most common worries we hear from patients in the first few weeks — and straightforward answers."},{type:"heading",level:3,text:'"I don\'t feel any better yet."'},{type:"text",body:"This is expected. Most antidepressants take 2-4 weeks to start working and 6-8 weeks for full effect. Your brain chemistry is adjusting gradually. Keep taking the medication as prescribed and come to your follow-up so we can assess your progress."},{type:"heading",level:3,text:'"I\'m having mild side effects — should I stop?"'},{type:"text",body:"Most mild side effects (nausea, headache, sleep changes) improve within the first 1-2 weeks. **Do not stop your medication because of mild side effects** without calling us first. If side effects are significant or not improving after a week, contact our office and we can make adjustments."},{type:"heading",level:3,text:'"I missed a dose — what do I do?"'},{type:"text",body:"Take it as soon as you remember, unless it is close to your next dose — in that case, skip the missed dose and continue on schedule. Do not double up. One missed dose will not undo your progress. If you are frequently forgetting, try setting a daily phone alarm."},{type:"heading",level:3,text:'"When should I message or call the office?"'},{type:"bullets",items:["Side effects that are significant or not improving after a week","You feel noticeably worse instead of better","New or increased anxiety, restlessness, or agitation","Any thoughts of self-harm (call immediately or call 988)","You want to stop your medication for any reason — talk to us first","You have a question and are not sure if it can wait until your next visit"]},{type:"callout",variant:"info",title:"There are no silly questions",body:"We would always rather hear from you than have you worry alone. Call our office at **(817) 431-9199** during business hours. If it is after hours and you are in crisis, call **988**."}]}],faqs:[{question:"How long until the medication starts working?",answer:"Most people begin noticing subtle improvements in 2-4 weeks, with full effects at 6-8 weeks. Sleep and energy often improve first, followed by mood. Be patient with the process — it takes time for your brain chemistry to adjust."},{question:"Will I feel different or not like myself?",answer:"The goal of medication is to help you feel more like yourself, not less. Most people describe it as the fog lifting — they can think more clearly, feel emotions more normally, and engage with life again. If you feel flat or numb, tell us — that usually means we need to adjust."},{question:"Can I drink alcohol while on these medications?",answer:"It's best to limit or avoid alcohol. Alcohol is a depressant and can worsen anxiety and depression. It can also increase side effects like drowsiness and dizziness. If you do drink, keep it moderate and pay attention to how you feel. Be honest with us about your alcohol use so we can factor it into your care."},{question:"What if I miss a dose?",answer:"Take it as soon as you remember, unless it's close to your next dose — in that case, skip the missed dose and resume your regular schedule. Never double up. Some medications (especially short-acting ones like venlafaxine) can cause withdrawal symptoms if missed, so try to take them consistently. Setting a daily phone alarm can help."},{question:"Are these medications addictive?",answer:"No. SSRIs, SNRIs, and bupropion are not addictive and do not cause cravings or euphoria. They are different from benzodiazepines (like Xanax) or opioids. When it's time to stop, we taper gradually to prevent withdrawal symptoms, but this is a physical adjustment — not addiction."},{question:"Will I need medication forever?",answer:"Not necessarily. Many people take medication for 6-12 months (or longer for recurrent episodes) and then taper off successfully. Others find that long-term medication is the right choice for them, and that's perfectly okay too. We'll reassess periodically and make decisions together."},{question:"Is therapy or medication better?",answer:"Research shows both are effective, and the combination often works best. Medication helps with the biological components — brain chemistry, sleep, energy — while therapy provides tools for managing thoughts, behaviors, and stress. They complement each other. We can help you decide what's right for your situation."},{question:"Will I gain weight?",answer:"Some medications can cause modest weight changes, while others (like bupropion) are weight-neutral or even associated with slight weight loss. If weight is a concern for you, let us know — it factors into which medication we recommend. Lifestyle habits like regular exercise and balanced nutrition also help."},{question:"What about sexual side effects?",answer:"Sexual side effects (lower desire, difficulty with arousal or orgasm) can occur with SSRIs and SNRIs. This is common and nothing to be embarrassed about. If it happens, we have options: adjusting the dose, switching medications, or adding bupropion. Please bring it up — we want to help."},{question:"Can I stop taking medication on my own?",answer:"Please don't stop abruptly without talking to us. Suddenly stopping can cause uncomfortable withdrawal symptoms (dizziness, nausea, irritability, \"brain zaps\"). When it's time to stop, we'll create a gradual tapering plan to minimize these effects. Even if you're feeling great, that can be a sign the medication is working — not that you no longer need it."},{question:"What if the first medication doesn't work?",answer:"It's very common to need to try more than one medication or adjust the dose. Everyone's brain chemistry is different. If one medication isn't helping after an adequate trial (usually 6-8 weeks at a therapeutic dose), we'll try a different one. There are many options, and we'll find what works for you."},{question:"What if I'm pregnant or planning to become pregnant?",answer:"Some medications are considered safer during pregnancy than others. If you're pregnant, planning to become pregnant, or breastfeeding, let us know right away. We'll weigh the risks and benefits together — untreated depression during pregnancy also carries risks, so stopping medication isn't always the safest choice."},{question:"Can I drive or work normally on these medications?",answer:"Most people can drive and work normally. Some people experience drowsiness or dizziness in the first few days, so use caution until you know how the medication affects you. If side effects interfere with daily activities, let us know — we can adjust."},{question:"What about supplements or natural alternatives?",answer:"Some supplements (like omega-3 fatty acids, vitamin D, and SAMe) have modest evidence for mood support. However, they're not substitutes for proven treatments in moderate to severe cases. St. John's Wort can interact dangerously with prescription antidepressants. Always tell us about any supplements you take so we can check for interactions."},{question:"Does anxiety or depression run in families?",answer:"There is a genetic component — having a close family member with anxiety or depression increases your risk. But genes are not destiny. Environment, life experiences, coping skills, and treatment all play major roles. Understanding your family history helps us provide better care, so share this information at your appointment."}],resources:[{title:"Medication Guide",description:"Printable reference sheet with medication names, doses, and tips for each medication we commonly prescribe.",type:"pdf"},{title:"Self-Care Checklist",description:"Daily checklist for sleep, exercise, mindfulness, and social connection to support your mental health.",type:"pdf"},{title:"Crisis Resources",description:"Complete list of local and national crisis hotlines, text lines, and emergency contacts.",type:"link",url:"https://988lifeline.org"},{title:"Mindfulness Guide",description:"Beginner-friendly introduction to mindfulness and grounding exercises for anxiety and depression.",type:"link",url:"https://www.mindful.org/how-to-meditate/"}],updates:[{title:"New provider availability for medication management",date:"2026-03-22",summary:"We've expanded appointment availability for mental health medication management visits. Same-week appointments are now available most weeks."},{title:"Updated medication comparison information",date:"2026-03-15",summary:"We've updated our medication guide to include the latest prescribing information and side effect profiles for SSRIs, SNRIs, and bupropion."},{title:"Self-care resources added",date:"2026-03-08",summary:"New downloadable self-care checklist and mindfulness guide added to the Resources section. Print them out or save them to your phone."}],nextSteps:[{title:"Schedule Follow-Up",description:"Book your next appointment to check in on your progress and adjust your treatment plan.",action:"Schedule Now",href:"tel:8174319199"},{title:"Contact Our Office",description:"Have a question between appointments? Reach us at (817) 431-9199 during business hours.",action:"Call Office",href:"tel:8174319199"},{title:"Request Refill",description:"Need a medication refill? Contact our office or request through your patient portal.",action:"Request Refill",href:"tel:8174319199"},{title:"Message Provider",description:"Send a message to your provider through the patient portal for non-urgent questions.",action:"Open Portal"}]};function r(){return(0,i.jsx)(n.Suspense,{children:(0,i.jsx)(a.oP,{config:s})})}}},function(e){e.O(0,[197,115,364,744],function(){return e(e.s=997)}),_N_E=e.O()}]);